#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define ABS(x)          (((x) > 0.0f) ? (x) : (-(x)))
#define ETA 0.3f       
#define MOMENTUM 0.3f  
#define WIDTH 16  
#define HEIGHT 16 
#define BLOCK_SIZE 16

inline float squash(float x) {
    return 1.0f / (1.0f + exp(-x));
}

__kernel void bpnn_layerforward_ocl(__global const float* l1, __global float* l2, __global const float* conn,
                                   __global float* partial_sum,
                                   __local float* l1_cache,
                                   __local float* conn_cache,
                                   const int n1, const int n2)
{
    // l1 size = n1+1
    // l2 size = n2+1
    // conn size = (n1+1)*(n2+1)
    // partial_sum size = number of blocks * WIDTH

    // This kernel computes hidden layer sums in a tiled manner.

    int tx = get_local_id(0);  // 0..BLOCK_SIZE-1
    int ty = get_local_id(1);  // 0..BLOCK_SIZE-1
    int bx = get_group_id(0);  // block id x
    int by = get_group_id(1);  // block id y

    int row = bx * BLOCK_SIZE + tx; // index in input layer (n1)
    int col = by * BLOCK_SIZE + ty; // index in hidden layer (n2)

    // Load input l1 vector to local memory
    if (ty == 0 && (row <= n1)) {
        l1_cache[tx] = l1[row];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    float sum = 0.0f;

    // Loop over tiles of conn matrix rows
    for (int i = 0; i < BLOCK_SIZE; i++) {
        int conn_row = bx * BLOCK_SIZE + i;
        int conn_col = by * BLOCK_SIZE + ty;

        // Check bounds
        if ((conn_row <= n1) && (conn_col <= n2)) {
            float w = conn[conn_row * (n2 + 1) + conn_col];
            float lv = l1_cache[i];
            sum += w * lv;
        }
    }

    // Each work-item stores partial sum for its col in partial_sum buffer
    int partial_index = bx * (n2) + col - 1; // partial_sum is indexed by block and col (offset by 1)

    if ((row <= n1) && (col >= 1) && (col <= n2)) {
        partial_sum[partial_index] = sum;
    }

    // One thread per column sums partial sums and applies squash
    // This is done outside kernel in host (since partial_sum is read back there)
}

__kernel void bpnn_adjust_weights_ocl(__global float* delta, const int ndelta,
                                     __global float* ly, const int nly,
                                     __global float* w, __global float* oldw)
{
    int j = get_global_id(0) + 1;  // 1..ndelta
    int k = get_global_id(1);      // 0..nly

    if (j <= ndelta && k <= nly) {
        int idx = k * (ndelta + 1) + j;
        float new_dw = (ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[idx]);
        w[idx] += new_dw;
        oldw[idx] = new_dw;
    }
}
